import{s}from"./supabase.DyS_ZLhl.js";document.addEventListener("astro:page-load",async()=>{const n=sessionStorage.getItem("sa_username");if(!n){window.location.href="/superadmin/login";return}const t=document.getElementById("sa-username");t&&(t.textContent=n);const{data:{session:o}}=await s.auth.getSession();if(!o){sessionStorage.removeItem("sa_username"),window.location.href="/superadmin/login";return}const e=document.getElementById("logout-btn");e&&e.addEventListener("click",async()=>{e.innerHTML="লগআউট হচ্ছে...",await s.auth.signOut(),sessionStorage.removeItem("sa_username"),window.location.href="/superadmin/login"})});
